{"command": "python3 << 'EOF'
with open('train.py', 'r') as f:
    lines = f.readlines()

# Change DEPTH
for i, line in enumerate(lines):
    if line.strip().startswith('DEPTH = 8'):
        lines[i] = 'DEPTH = 10               # number of transformer layers\n'
    elif line.strip().startswith('DEVICE_BATCH_SIZE = 128'):
        lines[i] = 'DEVICE_BATCH_SIZE = 32  # per-device batch size (reduce if OOM)\n'
    elif line.strip().startswith('EMBEDDING_LR = 0.6'):
        lines[i] = 'EMBEDDING_LR = 0.75      # learning rate for token embeddings (Adam)\n'
    elif line.strip().startswith('UNEMBEDDING_LR = 0.004'):
        lines[i] = 'UNEMBEDDING_LR = 0.0048  # learning rate for lm_head (Adam)\n'
    elif line.strip().startswith('MATRIX_LR = 0.04'):
        lines[i] = 'MATRIX_LR = 0.049        # learning rate for matrix parameters (Muon)\n'
    elif line.strip().startswith('SCALAR_LR = 0.5'):
        lines[i] = 'SCALAR_LR = 0.70         # learning rate for per-layer scalars (Adam)\n'
    elif line.strip().startswith('WEIGHT_DECAY = 0.2'):
        lines[i] = 'WEIGHT_DECAY = 0.16      # cautious weight decay for Muon\n'
    elif line.strip().startswith('ADAM_BETAS = (0.8, 0.95)'):
        lines[i] = 'ADAM_BETAS = (0.82, 0.95) # Adam beta1, beta2\n'
    elif line.strip().startswith('WARMDOWN_RATIO = 0.5'):
        lines[i] = 'WARMDOWN_RATIO = 0.40    # fraction of time budget for LR warmdown\n'
    elif line.strip().startswith('FINAL_LR_FRAC = 0.0'):
        lines[i] = 'FINAL_LR_FRAC = 0.10     # final LR as fraction of initial\n'

with open('train.py', 'w') as f:
    f.writelines(lines)

print("Modified for DEPTH=10 approach")
EOF
"}

